Here's a solid pattern for testing async code with MSTest, using `MockHttpMessageHandler` to control responses:

```csharp
[TestClass]
public class DataFetcherTests
{
    // MSTest natively supports async Task test methods
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new MockHttpMessageHandler("hello", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    // Use [Timeout] to guard against tests that hang
    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_ThrowsOnTimeout()
    {
        var handler = new MockHttpMessageHandler(delay: TimeSpan.FromSeconds(30));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(100));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsOnCancellation()
    {
        var handler = new MockHttpMessageHandler(delay: TimeSpan.FromSeconds(30));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsOnServerError()
    {
        var handler = new MockHttpMessageHandler("err", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }
}

// Lightweight fake — no mocking library needed
public class MockHttpMessageHandler : HttpMessageHandler
{
    private readonly string _content;
    private readonly HttpStatusCode _statusCode;
    private readonly TimeSpan? _delay;

    public MockHttpMessageHandler(string content = "", 
        HttpStatusCode statusCode = HttpStatusCode.OK,
        TimeSpan? delay = null)
    {
        _content = content;
        _statusCode = statusCode;
        _delay = delay;
    }

    protected override async Task<HttpResponseMessage> SendAsync(
        HttpRequestMessage request, CancellationToken cancellationToken)
    {
        if (_delay is { } d)
            await Task.Delay(d, cancellationToken);

        return new HttpResponseMessage(_statusCode)
        {
            Content = new StringContent(_content)
        };
    }
}
```

**Key takeaways:**

- **`async Task` test methods** — MSTest awaits them natively; no `.Result` or `.GetAwaiter()` needed
- **`[Timeout(ms)]`** — safeguards against hanging tests (especially important in CI)
- **`CancellationTokenSource`** — test both pre-cancelled and delayed-cancel scenarios
- **`MockHttpMessageHandler`** — subclass `HttpMessageHandler` directly to avoid needing Moq; the `Task.Delay` with the token correctly simulates cancellation during an in-flight request
